class ServiceStateTracker:
    """Tracks internal service state for debugging purposes."""

    def __init__(self):
        self.request_count = 0
        self.error_count = 0
        self.last_error = None
        self.last_error_time = None
        self.start_time = datetime.utcnow().isoformat()
        self.active_requests = {}
        self.method_call_counts = {}
        self.recent_errors = []

    def record_request(self, method_name, request_id):
        self.request_count += 1
        self.method_call_counts[method_name] = self.method_call_counts.get(method_name, 0) + 1
        self.active_requests[request_id] = {
            "method": method_name,
            "start_time": datetime.utcnow().isoformat(),
        }

    def complete_request(self, request_id):
        self.active_requests.pop(request_id, None)

    def record_error(self, method_name, error, request_id):
        self.error_count += 1
        self.last_error = str(error)
        self.last_error_time = datetime.utcnow().isoformat()
        error_record = {
            "method": method_name,
            "error": str(error),
            "error_type": type(error).__name__,
            "time": self.last_error_time,
            "request_id": request_id,
        }
        self.recent_errors.append(error_record)
        # Keep only last 50 errors
        if len(self.recent_errors) > 50:
            self.recent_errors = self.recent_errors[-50:]

    def get_state_snapshot(self):
        return {
            "total_requests": self.request_count,
            "total_errors": self.error_count,
            "error_rate": f"{(self.error_count / max(self.request_count, 1)) * 100:.2f}%",
            "active_requests": len(self.active_requests),
            "active_request_details": self.active_requests,
            "method_call_counts": self.method_call_counts,
            "last_error": self.last_error,
            "last_error_time": self.last_error_time,
            "service_uptime_since": self.start_time,
            "recent_errors_count": len(self.recent_errors),
            "recent_errors": self.recent_errors[-5:],  # Last 5 errors in snapshot
        }


def build_error_details(exception, method_name, request_id, state_tracker, extra_context=None):
    """Build comprehensive error details for debugging."""
    exc_type, exc_value, exc_tb = sys.exc_info()

    error_details = {
        "error_id": str(uuid.uuid4()),
        "request_id": request_id,
        "timestamp": datetime.utcnow().isoformat() + "Z",
        "service": "DebugGRPCService",
        "method": method_name,
        "error": {
            "type": type(exception).__name__,
            "message": str(exception),
            "module": type(exception).__module__,
            "args": [str(a) for a in exception.args],
        },
        "stack_trace": traceback.format_exception(exc_type, exc_value, exc_tb),
        "stack_frames": [],
        "service_state": state_tracker.get_state_snapshot(),
        "environment": {
            "python_version": sys.version,
            "pid": os.getpid(),
            "hostname": os.environ.get("HOSTNAME", "unknown"),
        },
    }

    # Extract detailed frame information
    if exc_tb:
        for frame_info in traceback.extract_tb(exc_tb):
            error_details["stack_frames"].append({
                "filename": frame_info.filename,
                "line_number": frame_info.lineno,
                "function": frame_info.name,
                "code": frame_info.line,
            })

    # Add local variables from the innermost frame
    if exc_tb:
        tb = exc_tb
        while tb.tb_next:
            tb = tb.tb_next
        local_vars = {}
        for key, value in tb.tb_frame.f_locals.items():
            try:
                local_vars[key] = repr(value)[:500]  # Truncate long repr
            except Exception:
                local_vars[key] = "<unrepresentable>"
        error_details["local_variables"] = local_vars

    if extra_context:
        error_details["extra_context"] = extra_context

    return error_details


def grpc_error_handler(method_name):
    """Decorator for comprehensive gRPC error handling."""

    def decorator(func):
        def wrapper(self, request, context):
            request_id = str(uuid.uuid4())
            self.state_tracker.record_request(method_name, request_id)
            start_time = time.time()

            # Add request metadata to logging context
            metadata = dict(context.invocation_metadata()) if hasattr(context, 'invocation_metadata') else {}

            logger.info(
                f"[{request_id}] Starting {method_name} | "
                f"Metadata: {json.dumps(metadata, default=str)}"
            )

            try:
                result = func(self, request, context, request_id=request_id)
                elapsed = time.time() - start_time
                logger.info(f"[{request_id}] Completed {method_name} in {elapsed:.4f}s")
                self.state_tracker.complete_request(request_id)
                return result

            except grpc.RpcError:
                # Re-raise if it's already a gRPC error (intentionally set by handler)
                self.state_tracker.complete_request(request_id)
                raise

            except ValueError as e:
                elapsed = time.time() - start_time
                self.state_tracker.record_error(method_name, e, request_id)

                error_details = build_error_details(
                    e, method_name, request_id, self.state_tracker,
                    extra_context={"elapsed_time": elapsed, "category": "validation_error"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)

                logger.error(f"[{request_id}] ValueError in {method_name}: {e}\n{error_json}")

                context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
                context.set_details(error_json)
                self.state_tracker.complete_request(request_id)
                return None

            except KeyError as e:
                elapsed = time.time() - start_time
                self.state_tracker.record_error(method_name, e, request_id)

                error_details = build_error_details(
                    e, method_name, request_id, self.state_tracker,
                    extra_context={"elapsed_time": elapsed, "category": "not_found"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)

                logger.error(f"[{request_id}] KeyError in {method_name}: {e}\n{error_json}")

                context.set_code(grpc.StatusCode.NOT_FOUND)
                context.set_details(error_json)
                self.state_tracker.complete_request(request_id)
                return None

            except PermissionError as e:
                elapsed = time.time() - start_time
                self.state_tracker.record_error(method_name, e, request_id)

                error_details = build_error_details(
                    e, method_name, request_id, self.state_tracker,
                    extra_context={"elapsed_time": elapsed, "category": "permission_denied"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)

                logger.error(f"[{request_id}] PermissionError in {method_name}: {e}\n{error_json}")

                context.set_code(grpc.StatusCode.PERMISSION_DENIED)
                context.set_details(error_json)
                self.state_tracker.complete_request(request_id)
                return None

            except TimeoutError as e:
                elapsed = time.time() - start_time
                self.state_tracker.record_error(method_name, e, request_id)

                error_details = build_error_details(
                    e, method_name, request_id, self.state_tracker,
                    extra_context={"elapsed_time": elapsed, "category": "timeout"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)

                logger.error(f"[{request_id}] TimeoutError in {method_name}: {e}\n{error_json}")

                context.set_code(grpc.StatusCode.DEADLINE_EXCEEDED)
                context.set_details(error_json)
                self.state_tracker.complete_request(request_id)
                return None

            except ZeroDivisionError as e:
                elapsed = time.time() - start_time
                self.state_tracker.record_error(method_name, e, request_id)

                error_details = build_error_details(
                    e, method_name, request_id, self.state_tracker,
                    extra_context={"elapsed_time": elapsed, "category": "arithmetic_error"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)

                logger.error(f"[{request_id}] ZeroDivisionError in {method_name}: {e}\n{error_json}")

                context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
                context.set_details(error_json)
                self.state_tracker.complete_request(request_id)
                return None

            except ConnectionError as e:
                elapsed = time.time() - start_time
                self.state_tracker.record_error(method_name, e, request_id)

                error_details = build_error_details(
                    e, method_name, request_id, self.state_tracker,
                    extra_context={"elapsed_time": elapsed, "category": "connection_error"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)

                logger.error(f"[{request_id}] ConnectionError in {method_name}: {e}\n{error_json}")

                context.set_code(grpc.StatusCode.UNAVAILABLE)
                context.set_details(error_json)
                self.state_tracker.complete_request(request_id)
                return None

            except Exception as e:
                elapsed = time.time() - start_time
                self.state_tracker.record_error(method_name, e, request_id)

                error_details = build_error_details(
                    e, method_name, request_id, self.state_tracker,
                    extra_context={"elapsed_time": elapsed, "category": "internal_error"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)

                logger.critical(
                    f"[{request_id}] Unhandled exception in {method_name}: "
                    f"{type(e).__name__}: {e}\n{error_json}"
                )

                context.set_code(grpc.StatusCode.INTERNAL)
                context.set_details(error_json)
                self.state_tracker.complete_request(request_id)
                return None

        return wrapper
    return decorator


class DebugServiceServicer(debug_service_pb2_grpc.DebugServiceServicer):
    """gRPC service with comprehensive error handling and debugging support."""

    def __init__(self):
        self.state_tracker = ServiceStateTracker()
        # Simulated database
        self._users = {
            "user_1": {"name": "Alice Johnson", "email": "alice@example.com"},
            "user_2": {"name": "Bob Smith", "email": "bob@example.com"},
            "user_3": {"name": "Charlie Brown", "email": "charlie@example.com"},
        }
        self._db_connected = True
        logger.info("DebugServiceServicer initialized")

    @grpc_error_handler("GetUser")
    def GetUser(self, request, context, request_id=None):
        """Get user by ID with detailed error handling."""
        user_id = request.user_id
        logger.debug(f"[{request_id}] Looking up user: {user_id}")

        if not user_id:
            raise ValueError("user_id cannot be empty")

        if user_id.startswith("restricted_"):
            raise PermissionError(f"Access denied to restricted user: {user_id}")

        if user_id == "slow_user":
            raise TimeoutError("Database query timed out after 30s while fetching user")

        # This will raise KeyError if user not found
        user_data = self._users[user_id]

        return debug_service_pb2.GetUserResponse(
            user_id=user_id,
            name=user_data["name"],
            email=user_data["email"],
        )

    @grpc_error_handler("ProcessData")
    def ProcessData(self, request, context, request_id=None):
        """Process data with various operations that may fail."""
        data = request.data
        operation = request.operation
        start = time.time()

        logger.debug(f"[{request_id}] Processing data with operation: {operation}")

        if not data:
            raise ValueError("Input data cannot be empty")

        if not operation:
            raise ValueError("Operation must be specified")

        valid_operations = ["uppercase", "lowercase", "reverse", "length", "json_parse"]

        if operation not in valid_operations:
            raise ValueError(
                f"Invalid operation '{operation}'. "
                f"Valid operations: {valid_operations}"
            )

        result = None
        if operation == "uppercase":
            result = data.upper()
        elif operation == "lowercase":
            result = data.lower()
        elif operation == "reverse":
            result = data[::-1]
        elif operation == "length":
            result = str(len(data))
        elif operation == "json_parse":
            # This will raise json.JSONDecodeError (subclass of ValueError) if invalid JSON
            parsed = json.loads(data)
            result = json.dumps(parsed, sort_keys=True)

        elapsed = time.time() - start

        return debug_service_pb2.ProcessDataResponse(
            result=result,
            processing_time=elapsed,
        )

    @grpc_error_handler("HealthCheck")
    def HealthCheck(self, request, context, request_id=None):
        """Health check endpoint with optional detailed state."""
        status = "HEALTHY"
        details = ""

        if request.include_details:
            state = self.state_tracker.get_state_snapshot()
            state["db_connected"] = self._db_connected
            state["users_in_cache"] = len(self._users)
            details = json.dumps(state, indent=2, default=str)

        return debug_service_pb2.HealthCheckResponse(
            status=status,
            details=details,
        )

    @grpc_error_handler("DivideNumbers")
    def DivideNumbers(self, request, context, request_id=None):
        """Divide two numbers - demonstrates arithmetic error handling."""
        numerator = request.numerator
        denominator = request.denominator

        logger.debug(f"[{request_id}] Dividing {numerator} / {denominator}")

        # This will raise ZeroDivisionError if denominator is 0
        # We intentionally use Python int division behavior to trigger the error
        if denominator == 0:
            raise ZeroDivisionError(
                f"Cannot divide {numerator} by zero. "
                f"Numerator was: {numerator}, Denominator was: {denominator}"
            )

        result = numerator / denominator

        return debug_service_pb2.DivideResponse(result=result)

    @grpc_error_handler("QueryDatabase")
    def QueryDatabase(self, request, context, request_id=None):
        """Simulate database queries with various failure modes."""
        query = request.query
        parameters = dict(request.parameters)

        logger.debug(f"[{request_id}] Executing query: {query} with params: {parameters}")

        if not self._db_connected:
            raise ConnectionError(
                "Database connection pool exhausted. "
                "No available connections after 10 retries."
            )

        if not query:
            raise ValueError("Query string cannot be empty")

        # Simulate SQL injection detection
        dangerous_keywords = ["DROP", "DELETE", "TRUNCATE"]
        for keyword in dangerous_keywords:
            if keyword in query.upper():
                raise PermissionError(
                    f"Dangerous SQL keyword '{keyword}' detected in query. "
                    f"Query rejected for safety. Full query: {query}"
                )

        # Simulate query execution
        if query.upper().startswith("SELECT"):
            # Simulate returning some data
            if "users" in query.lower():
                results = list(self._users.values())
                return debug_service_pb2.DatabaseQueryResponse(
                    result_json=json.dumps(results),
                    row_count=len(results),
                )
            elif "error_table" in query.lower():
                # Simulate an unexpected internal error
                internal_state = {"query": query, "params": parameters}
                raise RuntimeError(
                    f"Unexpected internal error during query execution. "
                    f"State: {json.dumps(internal_state)}"
                )
            elif "timeout_table" in query.lower():
                raise TimeoutError("Query execution exceeded maximum timeout of 30 seconds")
            else:
                return debug_service_pb2.DatabaseQueryResponse(
                    result_json=json.dumps([]),
                    row_count=0,
                )
        else:
            raise ValueError(f"Only SELECT queries are supported. Got: {query[:50]}")


def serve(port=50051):
    """Start the gRPC server."""
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        options=[
            ('grpc.max_send_message_length', 50 * 1024 * 1024),
            ('grpc.max_receive_message_length', 50 * 1024 * 1024),
        ]
    )
    servicer = DebugServiceServicer()
    debug_service_pb2_grpc.add_DebugServiceServicer_to_server(servicer, server)
    server.add_insecure_port(f'[::]:{port}')
    server.start()
    logger.info(f"Debug gRPC service started on port {port}")
    return server, servicer


